INSERT INTO profiles (slug, name, estado, servicios, description, website, tier, featured, cover, avatar, status) VALUES ('romina-hernandez', 'Romina Hernández', 'Ciudad de México', '["Diseño de Tipografía","Lettering","Ingeniería de Fuentes"]', '<p>Desde México, hago letras con amor y buen sazón. Tipografía a la medida, lettering e ingeniería en Tortilla.studio.</p><p>Trabajo con estudios, marcas y editoriales que buscan una voz tipográfica clara y con raíz mexicana — desde logotipos hasta familias completas para texto corrido.</p><p>Talleres, charlas y colaboraciones con el Colegio de Diseñadores y eventos como TMX. Si tienes un proyecto, escríbeme.</p>', 'https://tortilla.studio', 'pro', 0, '/mock/cover-warm.svg', NULL, 'published');
INSERT INTO profiles (slug, name, estado, servicios, description, website, tier, featured, cover, avatar, status) VALUES ('cristobal-henestrosa', 'Cristóbal Henestrosa', 'Ciudad de México', '["Diseño de Tipografía","Diseño Editorial"]', '<p>Diseñador tipográfico y editorial. Fuentes para prensa, libros e identidad cultural mexicana.</p><p>He diseñado tipos para periódicos, museos y sellos independientes. Me interesa la legibilidad, el detalle y la historia detrás de cada letra.</p>', 'https://henestrosatype.com', 'pro', 0, '/mock/cover-cool.svg', NULL, 'published');
INSERT INTO profiles (slug, name, estado, servicios, description, website, tier, featured, cover, avatar, status) VALUES ('miguel-contreras', 'Miguel Contreras', 'Puebla', '["Lettering","Branding","Diseño de Tipografía","Caligrafía"]', '<p>Lettering, caligrafía y tipografía para marcas. Proyectos de identidad con trazo propio.</p><p>Desde Puebla trabajo con restaurantes, cervecerías y proyectos culturales que necesitan letras con carácter — mural, empaque o sistema completo.</p><p>Disponible para colaboraciones en México y remoto.</p>', 'https://miglconts.com', 'pro', 0, '/mock/cover-green.svg', '/mock/miguel-avatar.png', 'published');
INSERT INTO profiles (slug, name, estado, servicios, description, website, tier, featured, cover, avatar, status) VALUES ('cecilia-del-castillo', 'Cecilia del Castillo', 'Fuera de México', '["Diseño de Tipografía","Caligrafía"]', '<p>Mexican type designer &amp; calligrapher. Fuentes y caligrafía para editorial e identidad.</p><p>Vivo entre proyectos editoriales y encargos de caligrafía para invitaciones, libros de artista y piezas de colección.</p>', 'https://www.instagram.com/ceci_dcd', 'free', 0, '/mock/cecilia-featured.png', NULL, 'published');
INSERT INTO profiles (slug, name, estado, servicios, description, website, tier, featured, cover, avatar, status) VALUES ('antonio-mejia-lechuga', 'Antonio Mejía Lechuga', 'Querétaro', '["Diseño Editorial"]', '<p>Diseño editorial y tipografía aplicada a libros, revistas y publicaciones independientes.</p><p>En Cuatro Ojos armamos publicaciones con ritmo, jerarquía y cuidado en cada página. Nos gusta el papel, la encuadernación y el detalle que se nota al hojear.</p>', 'https://cuatroojos.com.mx', 'free', 0, NULL, NULL, 'published');
INSERT INTO profiles (slug, name, estado, servicios, description, website, tier, featured, cover, avatar, status) VALUES ('giovanni-bautista', 'Giovanni Bautista', 'Oaxaca', '["Rotulación Manual","Lettering"]', '<p>Rotulación a mano y lettering para comercio local, fachadas y espacios públicos en Oaxaca.</p><p>Pintura, pincel y color para negocios de barrio, mercados y festivales. Cada letrero cuenta la historia del lugar.</p>', NULL, 'free', 0, '/mock/mara-featured.png', NULL, 'published');
INSERT INTO profiles (slug, name, estado, servicios, description, website, tier, featured, cover, avatar, status) VALUES ('mara-osman', 'Mara Osman', 'Ciudad de México', '["Branding","Diseño de Tipografía","Lettering","Caligrafía"]', '<p>Identidad tipográfica, lettering y caligrafía para marcas culturales y editoriales.</p><p>Combino investigación, boceto y sistema para que la voz de una marca se sienta coherente en impreso y pantalla.</p><p>Proyectos recientes: festivales, sellos discográficos y identidad para espacios culturales en CDMX.</p>', NULL, 'pro', 0, '/mock/cover-cool.svg', NULL, 'published');
INSERT INTO profiles (slug, name, estado, servicios, description, website, tier, featured, cover, avatar, status) VALUES ('sandra-morales', 'Sandra Morales', 'Puebla', '["Rotulación Manual"]', '<p>Rotulación manual para negocios, letreros y piezas de señalética con carácter local.</p><p>Trabajo con comercios de Puebla que quieren verse auténticos — sin plantillas, con letra hecha a mano.</p>', NULL, 'free', 0, '/mock/cover-green.svg', NULL, 'published');
